// Runs a full real-transaction join -> contribute -> rotate -> payout cycle
// against the RoscaCircle + MockERC20 pair deployed to Polygon Amoy by
// `ignition/modules/RoscaCircle.ts` (see deployed_addresses.json). Uses two
// signers — the funded burner wallet (member A / member[0]) and a throwaway
// "member B" wallet (member[1]) generated by generate-member-b-wallet.mjs —
// pulling both private keys from the Hardhat dev keystore in-memory only,
// same pattern as verify-burner-wallet.mjs. Neither key is ever printed.
import { readFile } from "node:fs/promises";
import { spawn } from "node:child_process";
import { JsonRpcProvider, Wallet, Contract, formatUnits, parseEther, formatEther } from "ethers";

const RPC_URL = "https://polygon-amoy-bor-rpc.publicnode.com";
const MEMBER_B_FUNDING = parseEther("0.015"); // gas money for join + 2x approve + 2x contribute

function getDevKeystoreSecret(key) {
  return new Promise((resolve, reject) => {
    const child = spawn("npx", ["hardhat", "keystore", "get", key, "--dev"], {
      stdio: ["ignore", "pipe", "pipe"],
      shell: true,
    });
    let stdout = "";
    let stderr = "";
    child.stdout.on("data", (chunk) => { stdout += chunk.toString(); });
    child.stderr.on("data", (chunk) => { stderr += chunk.toString(); });
    child.on("error", reject);
    child.on("close", (code) => {
      if (code === 0) resolve(stdout.trim());
      else reject(new Error(`hardhat keystore get exited with code ${code}: ${stderr}`));
    });
  });
}

function explorerTx(hash) {
  return `https://amoy.polygonscan.com/tx/${hash}`;
}

async function logTx(label, txPromise) {
  const tx = await txPromise;
  const receipt = await tx.wait();
  console.log(`${label}: ${explorerTx(receipt.hash)} (block ${receipt.blockNumber}, status ${receipt.status === 1 ? "success" : "FAILED"})`);
  return receipt;
}

const deployed = JSON.parse(
  await readFile(new URL("../ignition/deployments/chain-80002/deployed_addresses.json", import.meta.url)),
);
const tokenAddress = deployed["RoscaCircle#MockERC20"];
const roscaAddress = deployed["RoscaCircle#RoscaCircle"];

const roscaArtifact = JSON.parse(
  await readFile(new URL("../artifacts/contracts/RoscaCircle.sol/RoscaCircle.json", import.meta.url)),
);
const tokenArtifact = JSON.parse(
  await readFile(new URL("../artifacts/contracts/mocks/MockERC20.sol/MockERC20.json", import.meta.url)),
);

const provider = new JsonRpcProvider(RPC_URL);

const keyA = await getDevKeystoreSecret("POLYGON_AMOY_PRIVATE_KEY");
const keyB = await getDevKeystoreSecret("AMOY_MEMBER_B_PRIVATE_KEY");
const memberA = new Wallet(keyA, provider);
const memberB = new Wallet(keyB, provider);

console.log(`Member A (burner, will become members[0]): ${memberA.address}`);
console.log(`Member B (throwaway, will become members[1]): ${memberB.address}`);
console.log(`MockERC20 (mUSDT): ${tokenAddress}`);
console.log(`RoscaCircle: ${roscaAddress}`);
console.log();

// --- Step 0: fund member B with a little POL for gas, if it hasn't been yet ---
const bBalance = await provider.getBalance(memberB.address);
if (bBalance < MEMBER_B_FUNDING) {
  console.log(`Funding member B with ${formatEther(MEMBER_B_FUNDING)} POL for gas...`);
  await logTx("Fund member B", memberA.sendTransaction({ to: memberB.address, value: MEMBER_B_FUNDING }));
} else {
  console.log(`Member B already funded (${formatEther(bBalance)} POL) — skipping funding tx.`);
}
console.log();

const tokenA = new Contract(tokenAddress, tokenArtifact.abi, memberA);
const tokenB = new Contract(tokenAddress, tokenArtifact.abi, memberB);
const roscaA = new Contract(roscaAddress, roscaArtifact.abi, memberA);
const roscaB = new Contract(roscaAddress, roscaArtifact.abi, memberB);

const contributionAmount = await roscaA.contributionAmount();
const memberCount = await roscaA.memberCount();
const mintAmount = contributionAmount * memberCount * 2n; // headroom for both rounds

// --- Step 1: mint mUSDT to both members (MockERC20.mint is unrestricted) ---
console.log(`Minting ${formatUnits(mintAmount, 6)} mUSDT to each member...`);
await logTx("Mint to member A", tokenA.mint(memberA.address, mintAmount));
await logTx("Mint to member B", tokenB.mint(memberB.address, mintAmount));
console.log();

// --- Step 2: approve RoscaCircle to pull contributions ---
console.log("Approving RoscaCircle to spend mUSDT...");
await logTx("Approve (member A)", tokenA.approve(roscaAddress, mintAmount));
await logTx("Approve (member B)", tokenB.approve(roscaAddress, mintAmount));
console.log();

// --- Step 3: join (order = payout order; A joins first -> members[0]) ---
console.log("Joining the circle...");
await logTx("Join (member A)", roscaA.join());
await logTx("Join (member B)", roscaB.join());
console.log(`locked: ${await roscaA.locked()}`);
console.log();

// --- Step 4: round 0 — both contribute, auto-payout to members[0] (member A) ---
console.log("Round 0: contributing...");
const balBeforeRound0 = await tokenA.balanceOf(memberA.address);
await logTx("Contribute round 0 (member A)", roscaA.contribute());
const round0PayoutReceipt = await logTx("Contribute round 0 (member B, triggers payout)", roscaB.contribute());
const balAfterRound0 = await tokenA.balanceOf(memberA.address);
console.log(`Member A mUSDT balance: ${formatUnits(balBeforeRound0, 6)} -> ${formatUnits(balAfterRound0, 6)} (pot = ${formatUnits(contributionAmount * memberCount, 6)})`);
console.log(`currentRound now: ${await roscaA.currentRound()}, completed: ${await roscaA.completed()}`);
console.log();

// --- Step 5: round 1 — both contribute again, auto-payout to members[1] (member B), circle completes ---
console.log("Round 1: contributing...");
const balBeforeRound1 = await tokenB.balanceOf(memberB.address);
await logTx("Contribute round 1 (member A)", roscaA.contribute());
const round1PayoutReceipt = await logTx("Contribute round 1 (member B, triggers payout)", roscaB.contribute());
const balAfterRound1 = await tokenB.balanceOf(memberB.address);
console.log(`Member B mUSDT balance: ${formatUnits(balBeforeRound1, 6)} -> ${formatUnits(balAfterRound1, 6)} (pot = ${formatUnits(contributionAmount * memberCount, 6)})`);
console.log(`currentRound now: ${await roscaA.currentRound()}, completed: ${await roscaA.completed()}`);
console.log();

console.log("=== Full cycle complete ===");
console.log(`RoscaCircle: ${explorerTxOrAddr(roscaAddress)}`);
console.log(`MockERC20:   ${explorerTxOrAddr(tokenAddress)}`);

function explorerTxOrAddr(addr) {
  return `https://amoy.polygonscan.com/address/${addr}`;
}
